function LBattleUnitGridData:IsRole()
    return self.unitType == BattleUnitType.Role
end

function LBattleUnitGridData:IsHero()
    return self.unitType == BattleUnitType.Hero
end

function LBattleUnitGridData:IsMonster()
    return self.unitType == BattleUnitType.Monster
end

function LBattleUnitGridData:GetRealRefId()
    if self.unitType == BattleUnitType.Monster then
        local monsterAttrRef = GameTable.MonsterAttrRef[self.refId]
        if monsterAttrRef then
            return monsterAttrRef.effectId
        else
            return self.refId
        end
    elseif self.roleSimpleInfo then
        local gender = self.roleSimpleInfo.gender
        local genderRef = GameTable.RoleGenderRef[gender]
        if genderRef then
            return tonumber(genderRef.model)
        else
            return self.refId
        end
    else
        return self.refId
    end
end

return LBattleUnitGridData